## 📌 Script: `haversine.pl`

```perl
#!/usr/bin/perl
use strict;
use warnings;
use Getopt::Long;
use JSON;

# Define constants
my $KILOMETERS = 1;
my $MILES = 1;

# Haversine formula
sub haversine_distance {
    my ($lat1, $lon1, $lat2, $lon2) = @_;
    my $R = 6371; # Earth radius in kilometers

    my $dlat = radians($lat2 - $lat1);
    my $dlon = radians($lon2 - $lat2);

    my $a = sin($dlat/2)**2 + cos(radians($lat1)) * cos(radians($lat2)) * sin($dlon/2)**2;
    my $c = 2 * atan2(sqrt($a), sqrt(1 - $a));
    my $distance = $R * $c;

    return $distance;
}

# Convert degrees to radians
sub radians {
    return $_[0] * pi() / 180;
}

# Example locations
my %EXAMPLE_LOCATIONS = (
    'London' => { lat => 51.5074, lon => -0.1278 },
    'New York' => { lat => 40.7128, lon => -74.0060 },
    'Tokyo' => { lat => 35.6895, lon => 139.6917 },
    'Sydney' => { lat => -33.8688, lon => 151.2093 },
);

# Main script
my $input = shift || die "Usage: $0 <location1> <lat1> <lon1> <location2> <lat2> <lon2>\n";

# Parse input
my ($loc1, $lat1, $lon1, $loc2, $lat2, $lon2) = split(/\s+/,$input, 6);

# Validate input
if (!defined $loc1 || !defined $lat1 || !defined $lon1 || !defined $loc2 || !defined $lat2 || !defined $lon2) {
    die "Invalid input: Please provide two locations and their coordinates.\n";
}

# Check if location exists
my %locations = map { $_ => { lat => $EXAMPLE_LOCATIONS{$_}{lat}, lon => $EXAMPLE_LOCATIONS{$_}{lon} } } ($loc1, $loc2);

# Validate location data
foreach my $loc (@$locations) {
    if (!defined $locations{$loc}) {
        die "Location $loc is not found in the database.\n";
    }
}

# Calculate distance
my $distance = haversine_distance($locations{$loc1}{lat}, $locations{$loc1}{lon}, $locations{$loc2}{lat}, $locations{$loc2}{lon});

# Output
print "Distance between $loc1 and $loc2: \n";

# Output in kilometers or miles
my $unit = $KILOMETERS;
print "Distance: $distance $unit\n";

# Optional: Print in miles
if ($unit == $MILES) {
    my $earth_radius_miles = 3959;
    my $distance_miles = $distance * $earth_radius_miles / 1000;
    print "Distance: $distance_miles miles\n";
}

# Optional: Print location names
