```swift
import Foundation

// Define a Node structure for the BST
struct Node {
    var value: Int
    var left: Node?
    var right: Node?

    init(_ value: Int) {
        self.value = value
        self.left = nil
        self.right = nil
    }
}

// Define the BST class
class BinarySearchTree {
    var root: Node?

    // Insert a new node into the BST
    func insert(_ value: Int) {
        root = insertNode(root, value)
    }

    // Helper function to insert a node into the BST
    private func insertNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return Node(value)
        }

        if value < node!.value {
            node!.left = insertNode(node!.left, value)
        } else if value > node!.value {
            node!.right = insertNode(node!.right, value)
        }

        return node
    }

    // Delete a node from the BST
    func delete(_ value: Int) {
        root = deleteNode(root, value)
    }

    // Helper function to delete a node from the BST
    private func deleteNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return nil
        }

        if value < node!.value {
            node!.left = deleteNode(node!.left, value)
        } else if value > node!.value {
            node!.right = deleteNode(node!.right, value)
        } else {
            // Node found, delete it
            if node!.left == nil {
                return node!.right
            } else if node!.right == nil {
                return node!.left
            } else {
                // Node has two children, find the in-order successor
                let successor = findMinNode(node!.right)!
                node!.value = successor.value
                node!.right = deleteNode(node!.right, successor.value)
            }
        }

        return node
    }

    // Find the minimum value in a subtree
    private func findMinNode(_ node: Node?) -> Node? {
        var current = node
        while current?.left != nil {
            current = current!.left
        }
        return current
    }

    // Traversal functions
    // Pre-order traversal: visit node, then left, then right
    func preOrderTraverse() {
        preOrderTraverse(root)
    }

    private func preOrderTraverse(_ node: Node?) {
        if node != nil {
            print("Visit: $node!.value")
            preOrderTraverse(node!.left)
            preOrderTraverse(node!.right)
        }
    }

    // In-order traversal: left, visit node, right
    func inOrderTraverse() {
        inOrderTraverse(root)
    }

    private func inOrderTraverse(_ node: Node?) {
        if node != nil {
            inOrderTraverse(node!.left)
            print("Visit: $node!.value")
            inOrderTraverse(node!.right)
        }
    }

    // Post-order traversal: left, right, visit node
    func postOrderTraverse() {
        postOrderTraverse(root)
    }

    private func postOrderTraverse(_ node: Node?) {
        if node != nil {
            postOrderTraverse(node!.left)
            postOrderTraverse(node!.right)
            print("Visit: $node!.value")
        }
    }
}
```

### Explanation:

- **Node Structure**: Each node contains a value and pointers to its left and right children.
- **Insertion**: The `insert` method adds a new node to the correct position in the BST, maintaining the BST property.
- **Deletion**: The `delete` method removes a node while preserving the BST structure. It handles three cases: one-child nodes, two-child nodes, and nodes with no children.
- **Traversal**:
  - **Pre-order**: Visit the node first, then traverse the left subtree, then the right subtree.
  - **In-order**: Traverse the left subtree, visit the node, then traverse the right subtree.
  - **Post-order**: Traverse the left subtree, traverse the right subtree, then visit the node.

### Efficiency:
- **Insertion and Deletion**: O(log n) in average case, O(n) in worst case (e.g., when the tree is skewed).
- **Traversal**: O(n) for all three traversal types, as they visit all nodes exactly once.

This implementation is clean, efficient, and follows the standard BST operations.

