use strict;
use warnings;

# Function to merge two sorted arrays into one sorted array in descending order
sub merge {
    my ($left, $right) = @_;
    my @merged;

    # Base case: if either array is empty, return the other
    return $left if !@$left;
    return $right if !@$right;

    # If left array is empty, return right array
    return $right if !@$left;

    # If right array is empty, return left array
    return $left if !@$right;

    # Compare the first elements of both arrays
    if ($left->[0] >= $right->[0]) {
        # Add the first element of the left array to the merged array
        push @merged, $left->[0];
        return merge($left->[1], $right);
    } else {
        # Add the first element of the right array to the merged array
        push @merged, $right->[0];
        return merge($left, $right->[1]);
    }
}

# Function to perform merge sort on an array
sub merge_sort {
    my ($array) = @_;
    return $array if @$array == 0;

    # Base case: if the array has only one element, return it
    return $array if @$array == 1;

    # Split the array into two halves
    my $mid = int(@$array / 2);
    my $left = [$array[0..$mid - 1]];
    my $right = [$array[$mid..@$array - 1]];

    # Recursively sort both halves
    my $left_sorted = merge_sort($left);
    my $right_sorted = merge_sort($right);

    # Merge the two sorted halves
    my $merged = merge($left_sorted, $right_sorted);

    return $merged;
}

# Main program
