    foreach my $num (@numbers) {
        if (!defined($num) || $num !~ m/^-?\d+/) {
            $valid = 0;
            last;
        }
    }

    # If input is invalid, print an error message
    if (!$valid) {
        print "Invalid input. Please enter only integers.\n";
        next;
    }

    # Add the numbers to the array
    push @input, @numbers;
}

